// CLX Voice Outreach v1 — Resolve input
// Schedule Trigger = batch mode (downstream pulls Campaign Assigned +
// preferred_channel=voice). Manual Webhook = single-lead mode.

const input = $input.item.json;
const leadId = (input.body && input.body.lead_id) || input.lead_id || null;

return {
  json: {
    lead_id: leadId,
    mode: leadId ? 'single' : 'batch'
  }
};

// CLX Voice Outreach v1 — Normalize + preflight gates
// Skip gates:
//   1. lead row missing
//   2. preferred_channel is not 'voice'
//   3. no callable phone number (direct_phone or mobile_phone)
//   4. already attempted voice on this lead

const rows = $input.item.json;
const lead = Array.isArray(rows) ? rows[0] : rows;

if (!lead || !lead.id) {
  return { json: { _skip: true, skip_reason: 'lead_not_found' } };
}
if (String(lead.preferred_channel || '').toLowerCase() !== 'voice') {
  return { json: { _skip: true, skip_reason: 'preferred_channel_mismatch', lead_id: lead.id } };
}
const phone = lead.direct_phone || lead.mobile_phone || null;
if (!phone) {
  return { json: { _skip: true, skip_reason: 'no_phone_number', lead_id: lead.id, client_id: lead.client_id || null } };
}
const attempted = Array.isArray(lead.channels_attempted) ? lead.channels_attempted : [];
if (attempted.includes('voice')) {
  return { json: { _skip: true, skip_reason: 'already_attempted_voice', lead_id: lead.id, client_id: lead.client_id || null } };
}

// Normalise phone to E.164-ish digits only (Vapi will accept +NNNNNNN).
const digits = String(phone).replace(/[^0-9]/g, '');
const e164 = '+' + digits;

return { json: { ...lead, dial_phone: e164 } };

// CLX Voice Outreach v1 — Daily-cap gate
// 50/day/client in the migration; cap at 45 to leave headroom for retries
// and manual test calls on the same day.

const lead = $('Normalize Lead').first().json;
if (lead._skip) return { json: lead };

const used = Number($input.item.json) || 0;
const CAP = 45;

if (used >= CAP) {
  return { json: { _skip: true, skip_reason: 'voice_daily_cap_exceeded', calls_today: used, cap: CAP, lead_id: lead.id, client_id: lead.client_id || null } };
}

return { json: { ...lead, calls_today: used, cap: CAP } };

// CLX Voice Outreach v1 — DNCL gate
// check_dncl_status returns boolean — true means 'call allowed', false
// means the phone is on the Do-Not-Call List. On false, short-circuit
// with a VOICE_DNCL_BLOCKED skip so scan_errors fires the configured
// critical alert (migration §8).

const lead = $('Daily Cap Gate').first().json;
if (lead._skip) return { json: lead };

const allowed = $input.item.json;
const allowedBool = allowed === true || allowed === 'true';

if (!allowedBool) {
  return { json: { _skip: true, skip_reason: 'voice_dncl_blocked', lead_id: lead.id, client_id: lead.client_id || null, dial_phone: lead.dial_phone } };
}

return { json: lead };

// CLX Voice Outreach v1 — Compose script
// Interpolates {city}, {company}, {first_name} placeholders into the
// voice_script_template from the niche overlay. Falls back to a generic
// opener if the niche has no template seeded.

const lead = $('DNCL Gate').first().json;
const overlayRows = $input.item.json;
const overlay = Array.isArray(overlayRows) ? overlayRows[0] : overlayRows;

const firstName = (lead.full_name || '').split(' ')[0] || 'there';
const fallback = `Hi, this is Mary from Crystallux. I work with ${lead.industry || 'businesses'} in ${lead.city || 'your area'} and I have a quick opportunity to share. Can I send you a Calendly link to grab 20 minutes this week?`;

const template = (overlay && overlay.voice_script_template) || fallback;

const first_message = template
  .replace(/\{city\}/g, lead.city || 'your area')
  .replace(/\{company\}/g, lead.company || 'your company')
  .replace(/\{first_name\}/g, firstName);

return {
  json: {
    ...lead,
    first_message
  }
};

// CLX Voice Outreach v1 — Parse Vapi response
// Vapi returns { id, status, ... } on success. A 200 with id is enough to
// mark the call as queued; actual outcome arrives via the result webhook.

const resp = $input.item.json || {};
const lead = $('Compose Script').first().json;

const call_id = resp.id || null;
const ok = !!call_id;
const error_message = ok ? null : (resp.message || resp.error || JSON.stringify(resp).slice(0, 500));

return {
  json: {
    ...lead,
    vapi_ok: ok,
    vapi_call_id: call_id,
    vapi_error: error_message
  }
};

// CLX Voice Outreach v1 — Prep lead update
// Appends voice to channels_attempted. On initiate success, lead_status
// becomes 'Call Initiated' (the voice-result webhook later flips this
// to 'Replied' if the call outcome indicates consent to follow up).

const parsed = $('Parse Vapi Response').first().json;
const lead = $('Compose Script').first().json;

const attempted = Array.isArray(lead.channels_attempted) ? [...lead.channels_attempted] : [];
if (!attempted.includes('voice')) attempted.push('voice');

const body = {
  p_lead_id: lead.id,
  p_fields: {
    channels_attempted: attempted,
    last_channel_attempted: 'voice',
    last_channel_attempted_at: new Date().toISOString(),
    lead_status: parsed.vapi_ok ? 'Call Initiated' : 'Campaign Assigned'
  }
};

return { json: { ...parsed, rpc_body: JSON.stringify(body) } };
